def get_all_careers() -> list[dict[str, object]]:
    """Devuelve todas las carreras disponibles."""
    return CAREERS


def get_career_by_id(career_id: str) -> dict[str, object] | None:
    """Busca una carrera por su identificador."""
    return next((career for career in CAREERS if career["id"] == career_id), None)


def get_careers_by_area(area: str) -> list[dict[str, object]]:
    """Devuelve carreras cuya área coincide, ignorando mayúsculas y espacios."""
    normalized_area = area.strip().lower()
    return [career for career in CAREERS if str(career["area"]).lower() == normalized_area]
